import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { fetchAdminB2bCustomers, verifyB2bCustomer, setCustomerCredit } from "../../features/b2b/adminB2bSlice";
import { toast } from "react-toastify";
import { Link } from "react-router-dom";
import {
  Users, ShieldCheck, ShieldAlert, Search, ArrowLeft,
  CheckCircle2, XCircle, CreditCard, Building2, Loader2, ChevronDown
} from "lucide-react";

const AdminB2bCustomers = () => {
  const dispatch = useDispatch();
  const { customers, customersMeta, isLoading } = useSelector((s) => s.adminB2b);

  const [searchTerm, setSearchTerm] = useState("");
  const [verifiedFilter, setVerifiedFilter] = useState("");
  const [page, setPage] = useState(1);
  const [expandedId, setExpandedId] = useState(null);
  const [creditForm, setCreditForm] = useState({ creditLimit: "", paymentTerms: "" });

  const fetchCustomers = () => {
    const params = { page, limit: 20 };
    if (searchTerm) params.search = searchTerm;
    if (verifiedFilter !== "") params.isVerified = verifiedFilter;
    dispatch(fetchAdminB2bCustomers(params));
  };

  useEffect(() => { fetchCustomers(); }, [verifiedFilter, page]);

  const handleSearch = (e) => { e.preventDefault(); setPage(1); fetchCustomers(); };

  const handleVerify = async (id, action) => {
    try {
      await dispatch(verifyB2bCustomer({ id, action })).unwrap();
      toast.success(`Customer ${action === "approve" ? "approved" : "rejected"}`);
      fetchCustomers();
    } catch (err) { toast.error(err || "Action failed"); }
  };

  const handleSetCredit = async (id) => {
    if (!creditForm.creditLimit && !creditForm.paymentTerms) return;
    try {
      await dispatch(setCustomerCredit({
        id,
        creditLimit: creditForm.creditLimit ? parseFloat(creditForm.creditLimit) : undefined,
        paymentTerms: creditForm.paymentTerms || undefined,
      })).unwrap();
      toast.success("Credit settings updated");
      setCreditForm({ creditLimit: "", paymentTerms: "" });
      fetchCustomers();
    } catch (err) { toast.error(err || "Update failed"); }
  };

  return (
    <div className="min-h-screen bg-[#f8fafc]">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="mb-8">
          <Link to="/admin" className="flex items-center gap-1.5 text-sm font-bold text-slate-400 hover:text-indigo-600 mb-2">
            <ArrowLeft size={16} /> Admin Dashboard
          </Link>
          <h1 className="text-2xl font-black text-slate-900">B2B Customers</h1>
          <p className="text-sm text-slate-500 font-medium mt-1">
            Verify wholesale buyers, manage credit limits and payment terms
          </p>
        </div>

        {/* Filters */}
        <div className="bg-white rounded-3xl border border-slate-100 p-5 mb-6 shadow-sm flex flex-col sm:flex-row gap-4">
          <form onSubmit={handleSearch} className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input
              type="text"
              placeholder="Search by name, email, institution, license..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="pl-10 pr-4 h-10 w-full bg-slate-50 border border-slate-200 rounded-xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-indigo-500/20"
            />
          </form>
          <select
            value={verifiedFilter}
            onChange={(e) => { setVerifiedFilter(e.target.value); setPage(1); }}
            className="h-10 px-4 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold text-slate-600"
          >
            <option value="">All Customers</option>
            <option value="true">Verified</option>
            <option value="false">Pending Verification</option>
          </select>
        </div>

        {/* Customer List */}
        {isLoading ? (
          <div className="flex items-center justify-center py-24">
            <Loader2 size={32} className="text-indigo-600 animate-spin" />
          </div>
        ) : customers?.length > 0 ? (
          <div className="flex flex-col gap-4">
            {customers.map((cust) => {
              const isExpanded = expandedId === cust.id;
              return (
                <div key={cust.id} className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
                  <div
                    className="p-5 flex flex-col sm:flex-row sm:items-center gap-4 cursor-pointer hover:bg-slate-50/50 transition-colors"
                    onClick={() => setExpandedId(isExpanded ? null : cust.id)}
                  >
                    <div className="flex items-center gap-3 flex-1 min-w-0">
                      <div className={`w-10 h-10 rounded-2xl flex items-center justify-center ${
                        cust.isVerified ? "bg-emerald-50 text-emerald-600" : "bg-amber-50 text-amber-600"
                      }`}>
                        {cust.isVerified ? <ShieldCheck size={18} /> : <ShieldAlert size={18} />}
                      </div>
                      <div className="min-w-0">
                        <span className="font-extrabold text-slate-900 text-sm block truncate">
                          {cust.institutionName || `${cust.firstname} ${cust.lastname}`}
                        </span>
                        <span className="text-[10px] text-slate-400 font-bold">
                          {cust.email} • {cust.customerType?.replace(/_/g, " ")}
                        </span>
                      </div>
                    </div>

                    <div className="flex items-center gap-3 flex-shrink-0">
                      <div className={`text-[9px] font-black uppercase px-2 py-0.5 rounded border ${
                        cust.isVerified ? "bg-emerald-50 text-emerald-700 border-emerald-100" : "bg-amber-50 text-amber-700 border-amber-100"
                      }`}>
                        {cust.isVerified ? "Verified" : "Pending"}
                      </div>
                      <div className="text-right">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Credit</span>
                        <span className="text-sm font-black text-slate-900">
                          {parseFloat(cust.creditLimit || 0).toLocaleString()} ETB
                        </span>
                      </div>
                      <ChevronDown size={16} className={`text-slate-400 transition-transform ${isExpanded ? "rotate-180" : ""}`} />
                    </div>
                  </div>

                  {isExpanded && (
                    <div className="border-t border-slate-100 p-5 bg-slate-50/50 space-y-4">
                      {/* Details */}
                      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 text-sm">
                        <div>
                          <span className="text-[10px] font-black text-slate-400 uppercase block">License #</span>
                          <span className="font-bold text-slate-800">{cust.businessLicenseNumber || "—"}</span>
                        </div>
                        <div>
                          <span className="text-[10px] font-black text-slate-400 uppercase block">TIN</span>
                          <span className="font-bold text-slate-800">{cust.taxIdentificationNumber || "—"}</span>
                        </div>
                        <div>
                          <span className="text-[10px] font-black text-slate-400 uppercase block">Contact</span>
                          <span className="font-bold text-slate-800">{cust.contactPersonName || "—"}</span>
                        </div>
                        <div>
                          <span className="text-[10px] font-black text-slate-400 uppercase block">Payment Terms</span>
                          <span className="font-bold text-slate-800">{cust.paymentTerms?.replace(/_/g, " ") || "—"}</span>
                        </div>
                      </div>

                      {/* Actions */}
                      <div className="flex flex-wrap gap-3 pt-3 border-t border-slate-200">
                        {!cust.isVerified && (
                          <>
                            <button
                              onClick={() => handleVerify(cust.id, "approve")}
                              className="flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-xl text-xs font-black uppercase hover:bg-emerald-700"
                            >
                              <CheckCircle2 size={14} /> Approve
                            </button>
                            <button
                              onClick={() => handleVerify(cust.id, "reject")}
                              className="flex items-center gap-2 px-4 py-2 bg-rose-100 text-rose-700 rounded-xl text-xs font-black uppercase hover:bg-rose-200"
                            >
                              <XCircle size={14} /> Reject
                            </button>
                          </>
                        )}
                        {cust.isVerified && (
                          <span className="flex items-center gap-1.5 text-xs font-bold text-emerald-600 bg-emerald-50 px-3 py-1.5 rounded-xl">
                            <CheckCircle2 size={12} /> Verified Buyer
                          </span>
                        )}
                      </div>

                      {/* Credit Settings */}
                      <div className="flex flex-col sm:flex-row items-start sm:items-center gap-3 pt-3 border-t border-slate-200">
                        <span className="text-xs font-bold text-slate-500 flex items-center gap-1.5">
                          <CreditCard size={12} /> Set Credit:
                        </span>
                        <input
                          type="number"
                          placeholder="Credit Limit (ETB)"
                          value={expandedId === cust.id ? creditForm.creditLimit : ""}
                          onChange={(e) => setCreditForm({ ...creditForm, creditLimit: e.target.value })}
                          className="h-8 px-3 border border-slate-200 rounded-lg text-xs font-medium w-40"
                        />
                        <select
                          value={expandedId === cust.id ? creditForm.paymentTerms : ""}
                          onChange={(e) => setCreditForm({ ...creditForm, paymentTerms: e.target.value })}
                          className="h-8 px-3 border border-slate-200 rounded-lg text-xs font-bold text-slate-600"
                        >
                          <option value="">Payment Terms...</option>
                          <option value="PREPAID">Prepaid Only</option>
                          <option value="NET_30">Net 30</option>
                          <option value="NET_60">Net 60</option>
                          <option value="NET_90">Net 90</option>
                        </select>
                        <button
                          onClick={() => handleSetCredit(cust.id)}
                          className="px-3 h-8 bg-indigo-600 text-white rounded-lg text-xs font-bold hover:bg-indigo-700"
                        >
                          Update
                        </button>
                      </div>
                    </div>
                  )}
                </div>
              );
            })}

            {customersMeta && customersMeta.pages > 1 && (
              <div className="flex items-center justify-center gap-2 mt-6">
                {Array.from({ length: customersMeta.pages }, (_, i) => i + 1).map((p) => (
                  <button
                    key={p}
                    onClick={() => setPage(p)}
                    className={`w-9 h-9 rounded-xl text-xs font-bold ${
                      p === page ? "bg-indigo-600 text-white" : "bg-white border border-slate-200 text-slate-600"
                    }`}
                  >
                    {p}
                  </button>
                ))}
              </div>
            )}
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center py-24 bg-white rounded-3xl border border-slate-100 shadow-sm">
            <Users size={48} className="text-slate-200 mb-4" />
            <p className="text-sm font-black text-slate-400 uppercase tracking-widest">No B2B customers found</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminB2bCustomers;
